function calculate({
    totalContentUnits, genderRepresentedUnits, racialEthnicRepresentedUnits,
    socioeconomicRepresentedUnits, disabilityRepresentedUnits,
    culturalGeographicRepresentedUnits, historicalPerspectiveUnits,
    depthOfIntegrationScore, targetOverallDiversityPercentage, penaltyForHomogeneity
}) {
    // Input validation and edge cases
    if (totalContentUnits <= 0) {
        return {
            inclusivityIndex: 0,
            demographicSubIndex: 0,
            culturalSubIndex: 0,
            historicalSubIndex: 0,
            message: "Total content units must be greater than zero."
        };
    }

    if (targetOverallDiversityPercentage <= 0 || targetOverallDiversityPercentage > 100) {
        return {
            inclusivityIndex: 0,
            demographicSubIndex: 0,
            culturalSubIndex: 0,
            historicalSubIndex: 0,
            message: "Target Diversity Percentage must be between 1 and 100."
        };
    }

    // Ensure represented units do not exceed total units and are non-negative
    const safeValue = (value) => Math.min(Math.max(0, value), totalContentUnits);

    const genderP = (safeValue(genderRepresentedUnits) / totalContentUnits) * 100;
    const racialP = (safeValue(racialEthnicRepresentedUnits) / totalContentUnits) * 100;
    const socioeconomicP = (safeValue(socioeconomicRepresentedUnits) / totalContentUnits) * 100;
    const disabilityP = (safeValue(disabilityRepresentedUnits) / totalContentUnits) * 100;
    const culturalP = (safeValue(culturalGeographicRepresentedUnits) / totalContentUnits) * 100;
    const historicalP = (safeValue(historicalPerspectiveUnits) / totalContentUnits) * 100;

    // Calculate individual category scores, capped at 120 for exceptional performance
    // Score is relative to the targetOverallDiversityPercentage
    const calculateCategoryScore = (actualP, targetP) => Math.min(120, (actualP / targetP) * 100);

    const genderScore = calculateCategoryScore(genderP, targetOverallDiversityPercentage);
    const racialScore = calculateCategoryScore(racialP, targetOverallDiversityPercentage);
    const socioeconomicScore = calculateCategoryScore(socioeconomicP, targetOverallDiversityPercentage);
    const disabilityScore = calculateCategoryScore(disabilityP, targetOverallDiversityPercentage);
    const culturalScore = calculateCategoryScore(culturalP, targetOverallDiversityPercentage);
    const historicalScore = calculateCategoryScore(historicalP, targetOverallDiversityPercentage);

    // Calculate sub-indices (average of related category scores)
    const demographicSubIndex = (genderScore + racialScore + socioeconomicScore + disabilityScore) / 4;
    const culturalSubIndex = culturalScore;
    const historicalSubIndex = historicalScore;

    // Depth of Integration Multiplier (scales 1-5 to a multiplier from 0.6 to 1.4)
    // This enhances or reduces the overall score based on the quality of integration
    const safeDepth = Math.min(Math.max(1, depthOfIntegrationScore), 5);
    const integrationMultiplier = 0.6 + (safeDepth - 1) * 0.2; // 1->0.6, 2->0.8, 3->1.0, 4->1.2, 5->1.4

    // Initial Inclusivity Index calculation: weighted average of sub-indices
    // Weights: Demographic (40%), Cultural (30%), Historical (30%)
    let inclusivityIndex = (
        demographicSubIndex * 0.4 +
        culturalSubIndex * 0.3 +
        historicalSubIndex * 0.3
    );

    // Apply Depth of Integration multiplier to the initial index
    inclusivityIndex *= integrationMultiplier;

    // Apply homogeneity penalty if overall average representation is very low
    // This triggers if the average of all category percentages is less than 20% of the target.
    const averageRepresentationPercentage = (genderP + racialP + socioeconomicP + disabilityP + culturalP + historicalP) / 6;
    const safePenalty = Math.max(1.0, penaltyForHomogeneity); // Ensure penalty factor is at least 1

    if (averageRepresentationPercentage < (targetOverallDiversityPercentage * 0.2)) {
        inclusivityIndex /= safePenalty;
    }

    // Ensure final index and sub-indices are non-negative and capped appropriately
    const finalInclusivityIndex = Math.min(Math.max(0, inclusivityIndex), 120);
    const finalDemographicSubIndex = Math.min(Math.max(0, demographicSubIndex), 120);
    const finalCulturalSubIndex = Math.min(Math.max(0, culturalSubIndex), 120);
    const finalHistoricalSubIndex = Math.min(Math.max(0, historicalSubIndex), 120);

    return {
        inclusivityIndex: parseFloat(finalInclusivityIndex.toFixed(2)),
        demographicSubIndex: parseFloat(finalDemographicSubIndex.toFixed(2)),
        culturalSubIndex: parseFloat(finalCulturalSubIndex.toFixed(2)),
        historicalSubIndex: parseFloat(finalHistoricalSubIndex.toFixed(2))
    };
}
